import { useTranslate } from '@/hooks/common-hooks';
import { useFormContext, useWatch } from 'react-hook-form';
import {
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from './ui/form';
import { RAGFlowSelect } from './ui/select';
import { Switch } from './ui/switch';

const parseMethodOptions = ['auto', 'txt', 'ocr'].map((value) => ({
  label: value,
  value,
}));

const languageOptions = [
  'English',
  'Chinese',
  'Traditional Chinese',
  'Russian',
  'Ukrainian',
  'Indonesian',
  'Spanish',
  'Vietnamese',
  'Japanese',
  'Korean',
  'Portuguese BR',
  'German',
  'French',
  'Italian',
  'Tamil',
  'Telugu',
  'Kannada',
  'Thai',
  'Greek',
  'Hindi',
].map((value) => ({ label: value, value }));

export function MinerUOptionsFormField() {
  const form = useFormContext();
  const { t } = useTranslate('knowledgeDetails');

  const layoutRecognize = useWatch({
    control: form.control,
    name: 'parser_config.layout_recognize',
  });

  const isMinerUSelected = layoutRecognize?.toLowerCase?.()?.includes('mineru');

  if (!isMinerUSelected) {
    return null;
  }

  return (
    <div className="space-y-3 border-l-2 border-primary/30 pl-4 ml-2">
      <div className="text-sm font-medium text-muted-foreground">
        {t('mineruOptions', 'MinerU Options')}
      </div>

      <FormField
        control={form.control}
        name="parser_config.mineru_parse_method"
        render={({ field }) => (
          <FormItem className=" items-center space-y-0 ">
            <div className="flex items-center gap-1">
              <FormLabel className="text-sm text-muted-foreground whitespace-break-spaces w-1/4">
                {t('mineruParseMethod', 'Parse method')}
              </FormLabel>
              <div className="w-3/4">
                <FormControl>
                  <RAGFlowSelect
                    {...field}
                    options={parseMethodOptions}
                    value={field.value || 'auto'}
                  ></RAGFlowSelect>
                </FormControl>
              </div>
            </div>
            <div className="flex pt-1">
              <div className="w-1/4"></div>
              <FormMessage />
            </div>
          </FormItem>
        )}
      />

      <FormField
        control={form.control}
        name="parser_config.mineru_lang"
        render={({ field }) => (
          <FormItem className=" items-center space-y-0 ">
            <div className="flex items-center gap-1">
              <FormLabel className="text-sm text-muted-foreground whitespace-break-spaces w-1/4">
                {t('mineruLanguage', 'Language')}
              </FormLabel>
              <div className="w-3/4">
                <FormControl>
                  <RAGFlowSelect
                    {...field}
                    options={languageOptions}
                    value={field.value || 'English'}
                  ></RAGFlowSelect>
                </FormControl>
              </div>
            </div>
            <div className="flex pt-1">
              <div className="w-1/4"></div>
              <FormMessage />
            </div>
          </FormItem>
        )}
      />

      <FormField
        control={form.control}
        name="parser_config.mineru_formula_enable"
        render={({ field }) => (
          <FormItem className=" items-center space-y-0 ">
            <div className="flex items-center gap-1">
              <FormLabel className="text-sm text-muted-foreground whitespace-break-spaces w-1/4">
                {t('mineruFormulaEnable', 'Formula recognition')}
              </FormLabel>
              <div className="w-3/4">
                <FormControl>
                  <Switch
                    checked={field.value ?? true}
                    onCheckedChange={field.onChange}
                  ></Switch>
                </FormControl>
              </div>
            </div>
            <div className="flex pt-1">
              <div className="w-1/4"></div>
              <FormMessage />
            </div>
          </FormItem>
        )}
      />

      <FormField
        control={form.control}
        name="parser_config.mineru_table_enable"
        render={({ field }) => (
          <FormItem className=" items-center space-y-0 ">
            <div className="flex items-center gap-1">
              <FormLabel className="text-sm text-muted-foreground whitespace-break-spaces w-1/4">
                {t('mineruTableEnable', 'Table recognition')}
              </FormLabel>
              <div className="w-3/4">
                <FormControl>
                  <Switch
                    checked={field.value ?? true}
                    onCheckedChange={field.onChange}
                  ></Switch>
                </FormControl>
              </div>
            </div>
            <div className="flex pt-1">
              <div className="w-1/4"></div>
              <FormMessage />
            </div>
          </FormItem>
        )}
      />
    </div>
  );
}
